// ─────────────────────────────────────────────────────────────────────────
//  Perfume image system
//  -----------------------------------------------------------------------
//  Dual-source: real product photos (uploaded to /public/perfumes/) when
//  available, otherwise an inline SVG placeholder with a brand-specific
//  bottle silhouette and brand monogram.
//
//  Real images take precedence — see `perfume-images.ts` for the manifest
//  generated by the admin upload flow at /admin/images.
// ─────────────────────────────────────────────────────────────────────────

import { perfumeImageManifest } from "./perfume-images";

// ────────────── Family palettes (background tints) ──────────────
type FamilyKey =
  | "blumig" | "blumig-oriental" | "blumig-amber" | "blumig-frisch"
  | "oriental" | "oriental-holzig" | "oriental-vanille" | "oriental-amber" | "oriental-blumig" | "oriental-wuerzig"
  | "holzig" | "holzig-aromatisch" | "holzig-wuerzig" | "holzig-frisch" | "holzig-blumig" | "holzig-aquatisch"
  | "frisch" | "frisch-wuerzig" | "fougere" | "chypre" | "chypre-blumig" | "chypre-fruchtig"
  | "fruchtig" | "fruchtig-chypre" | "fruchtig-gourmand"
  | "ledrig" | "ledrig-wuerzig" | "gourmand" | "aquatisch" | "aquatisch-aromatisch"
  | "aromatisch-fougere" | "aromatisch-frisch"
  | "default";

const FAMILY_PALETTES: Record<FamilyKey, { from: string; to: string; accent: string }> = {
  "blumig":               { from: "#f6ece5", to: "#e8d4c8", accent: "#b88c7a" },
  "blumig-oriental":      { from: "#efe2da", to: "#d8c0a8", accent: "#9b7456" },
  "blumig-amber":         { from: "#f5e9d2", to: "#e3c89a", accent: "#a87a3c" },
  "blumig-frisch":        { from: "#eef0e8", to: "#dce0d0", accent: "#7d8a72" },
  "oriental":             { from: "#efdcc0", to: "#d4b384", accent: "#8b5e2a" },
  "oriental-holzig":      { from: "#e8d4b0", to: "#c8a070", accent: "#7a4a1c" },
  "oriental-vanille":     { from: "#f0e2c4", to: "#d8b886", accent: "#8e6128" },
  "oriental-amber":       { from: "#eed7b0", to: "#d4ad72", accent: "#85571f" },
  "oriental-blumig":      { from: "#f0dcc4", to: "#d8b88a", accent: "#8a5e2e" },
  "oriental-wuerzig":     { from: "#e8d2b2", to: "#c89870", accent: "#7c4a1f" },
  "holzig":               { from: "#ece2d0", to: "#cfb98e", accent: "#7d5a30" },
  "holzig-aromatisch":    { from: "#e6e8df", to: "#c8ccba", accent: "#6e7560" },
  "holzig-wuerzig":       { from: "#ebdcc0", to: "#cba87a", accent: "#7d4f1f" },
  "holzig-frisch":        { from: "#e6ece0", to: "#c8d2b8", accent: "#6e7858" },
  "holzig-blumig":        { from: "#ece0c8", to: "#cdb38c", accent: "#7e5a35" },
  "holzig-aquatisch":     { from: "#e2e6e0", to: "#bcc6b8", accent: "#5a6f5a" },
  "frisch":               { from: "#e9eeec", to: "#cdd6d2", accent: "#5c726a" },
  "frisch-wuerzig":       { from: "#ece8de", to: "#d2cab7", accent: "#766a4f" },
  "fougere":              { from: "#e6ebe0", to: "#c4cdb8", accent: "#5e6e4a" },
  "chypre":               { from: "#ece4d0", to: "#cfbe96", accent: "#7c623c" },
  "chypre-blumig":        { from: "#eee0d0", to: "#d4b698", accent: "#7e5a3a" },
  "chypre-fruchtig":      { from: "#eedcc8", to: "#d2b288", accent: "#7a5430" },
  "fruchtig":             { from: "#f4e8d2", to: "#e2c898", accent: "#a36a30" },
  "fruchtig-chypre":      { from: "#efdcc0", to: "#d4b07a", accent: "#825030" },
  "fruchtig-gourmand":    { from: "#f5e0c8", to: "#e0b888", accent: "#8e5826" },
  "ledrig":               { from: "#e6d5c0", to: "#bf9874", accent: "#6e3f1f" },
  "ledrig-wuerzig":       { from: "#e2cfb6", to: "#b8906a", accent: "#683818" },
  "gourmand":             { from: "#f0dec5", to: "#dab891", accent: "#8b572c" },
  "aquatisch":            { from: "#e3eaee", to: "#bccad3", accent: "#4a6a7a" },
  "aquatisch-aromatisch": { from: "#e5ece8", to: "#c0d0c8", accent: "#506e60" },
  "aromatisch-fougere":   { from: "#e8eee0", to: "#cad6b8", accent: "#5e7048" },
  "aromatisch-frisch":    { from: "#e6ece6", to: "#c8d2c4", accent: "#5e7060" },
  "default":              { from: "#efe9df", to: "#d6cdbb", accent: "#7d6f5a" },
};

function familyKey(family?: string): FamilyKey {
  if (!family) return "default";
  const f = family.toLowerCase();
  // Exact-ish multi-word matches first
  if (f.includes("blumig") && f.includes("oriental")) return "blumig-oriental";
  if (f.includes("blumig") && f.includes("amber")) return "blumig-amber";
  if (f.includes("blumig") && f.includes("frisch")) return "blumig-frisch";
  if (f.includes("oriental") && f.includes("vanille")) return "oriental-vanille";
  if (f.includes("oriental") && f.includes("amber")) return "oriental-amber";
  if (f.includes("oriental") && f.includes("holzig")) return "oriental-holzig";
  if (f.includes("oriental") && f.includes("blumig")) return "oriental-blumig";
  if (f.includes("oriental") && f.includes("würz")) return "oriental-wuerzig";
  if (f.includes("holzig") && f.includes("würz")) return "holzig-wuerzig";
  if (f.includes("holzig") && f.includes("aroma")) return "holzig-aromatisch";
  if (f.includes("holzig") && f.includes("frisch")) return "holzig-frisch";
  if (f.includes("holzig") && f.includes("blumig")) return "holzig-blumig";
  if (f.includes("holzig") && f.includes("aqua")) return "holzig-aquatisch";
  if (f.includes("chypre") && f.includes("blumig")) return "chypre-blumig";
  if (f.includes("chypre") && f.includes("frucht")) return "chypre-fruchtig";
  if (f.includes("frucht") && f.includes("chypre")) return "fruchtig-chypre";
  if (f.includes("frucht") && f.includes("gourmand")) return "fruchtig-gourmand";
  if (f.includes("aqua") && f.includes("aroma")) return "aquatisch-aromatisch";
  if (f.includes("aroma") && (f.includes("fougère") || f.includes("fougere"))) return "aromatisch-fougere";
  if (f.includes("aroma") && f.includes("frisch")) return "aromatisch-frisch";
  if (f.includes("frisch") && f.includes("würz")) return "frisch-wuerzig";
  if (f.includes("ledrig") && f.includes("würz")) return "ledrig-wuerzig";
  // Single-word
  if (f.includes("blumig")) return "blumig";
  if (f.includes("oriental")) return "oriental";
  if (f.includes("holzig")) return "holzig";
  if (f.includes("frisch")) return "frisch";
  if (f.includes("fougère") || f.includes("fougere")) return "fougere";
  if (f.includes("chypre")) return "chypre";
  if (f.includes("frucht")) return "fruchtig";
  if (f.includes("ledrig") || f.includes("leder")) return "ledrig";
  if (f.includes("gourmand")) return "gourmand";
  if (f.includes("aqua")) return "aquatisch";
  return "default";
}

export function getFamilyGradient(family?: string): string {
  const p = FAMILY_PALETTES[familyKey(family)];
  return `linear-gradient(135deg, ${p.from} 0%, ${p.to} 100%)`;
}

export function getFamilyAccent(family?: string): string {
  return FAMILY_PALETTES[familyKey(family)].accent;
}

