// Brand → bottle template mapping. Falls back to "classic".
const BRAND_BOTTLES: Record<string, keyof typeof BOTTLES> = {
  // brand SLUGs (markeSlug)
  "tom-ford": "classic",
  "chanel": "classic",
  "versace": "classic",
  "burberry": "classic",
  "dior": "rounded",
  "ysl": "rounded",
  "creed": "rounded",
  "armani": "modern",
  "hermes": "modern",
  "bvlgari": "modern",
  "lancome": "modern",
  "le-labo": "apothecary",
  "diptyque": "apothecary",
  "byredo": "apothecary",
  "mfk": "flacon",
  "carolina-herrera": "stiletto", // Good Girl is iconic
  "paco-rabanne": "modern",
  "gucci": "rounded",
  "guerlain": "teardrop",
  "mugler": "teardrop",        // Alien (Angel handled per-perfume below)
  "jpg": "torso",              // Le Male
};

// Per-perfume overrides for iconic shapes (slug → bottle key)
const PERFUME_BOTTLES: Record<string, keyof typeof BOTTLES> = {
  "angel": "star",
  "alien": "teardrop",
  "shalimar": "teardrop",
  "le-male": "torso",
  "good-girl": "stiletto",
  "bad-boy": "modern",
};

function pickBottle(slug?: string, brandSlug?: string): keyof typeof BOTTLES {
  if (slug && PERFUME_BOTTLES[slug]) return PERFUME_BOTTLES[slug];
  if (brandSlug && BRAND_BOTTLES[brandSlug]) return BRAND_BOTTLES[brandSlug];
  return "classic";
}

// ────────────── Encoding ──────────────
function encodeSvg(svg: string): string {
  return (
    "data:image/svg+xml;charset=utf-8," +
    encodeURIComponent(svg.replace(/\s+/g, " ").trim())
  );
}

function brandMonogram(brand: string): string {
  return brand
    .split(/\s+/)
    .filter((w) => w.length > 1 && !/^(de|du|la|le|el|of|the|by|&)$/i.test(w))
    .slice(0, 2)
    .map((w) => w[0].toUpperCase())
    .join("");
}

// ────────────── Public API ──────────────
type GenerateOpts = {
  brand: string;
  name: string;
  family?: string;
  slug?: string;
  brandSlug?: string;
  width?: number;
  height?: number;
};

/** Generates an editorial SVG placeholder with a brand-specific bottle. */
export function generatePerfumeImage(opts: GenerateOpts): string {
  const { brand, family, slug, brandSlug, width = 600, height = 800 } = opts;
  const palette = FAMILY_PALETTES[familyKey(family)];
  const monogram = brandMonogram(brand);
  const bottleKind = pickBottle(slug, brandSlug);
  const bottle = BOTTLES[bottleKind](palette.accent);

  // The bottle paths are designed for a 400×600 internal coordinate system,
  // centered. We render at the requested aspect by stretching the viewBox.
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 400 600" width="${width}" height="${height}" preserveAspectRatio="xMidYMid slice">
    <defs>
      <linearGradient id="bg" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stop-color="${palette.from}"/>
        <stop offset="100%" stop-color="${palette.to}"/>
      </linearGradient>
      <radialGradient id="vignette" cx="50%" cy="50%" r="65%">
        <stop offset="60%" stop-color="white" stop-opacity="0"/>
        <stop offset="100%" stop-color="${palette.accent}" stop-opacity="0.10"/>
      </radialGradient>
    </defs>
    <rect width="400" height="600" fill="url(#bg)"/>
    <rect width="400" height="600" fill="url(#vignette)"/>
    ${bottle}
    <text x="200" y="555" text-anchor="middle"
      font-family="Georgia, 'Playfair Display', serif"
      font-size="38" letter-spacing="0.08em"
      fill="${palette.accent}" fill-opacity="0.14"
      font-weight="500">${monogram}</text>
  </svg>`;
  return encodeSvg(svg);
}

export function generatePerfumeBanner(opts: Omit<GenerateOpts, "width" | "height">): string {
  return generatePerfumeImage({ ...opts, width: 1200, height: 800 });
}

// ────────────── Real-image lookup ──────────────
/** Returns the path under /perfumes/ if a real image was uploaded for this slug. */
export function realImageFor(slug: string): string | null {
  const ext = perfumeImageManifest[slug];
  return ext ? `/perfumes/${slug}.${ext}` : null;
}

/**
 * Convenience wrapper used everywhere a perfume image is needed.
 * Returns either the real product photo URL or a generated SVG fallback.
 */
export function imageFor(
  parfum: {
    marke: string;
    name: string;
    slug?: string;
    markeSlug?: string;
    duftfamilie?: string;
  },
  size: "card" | "banner" = "card",
): string {
  if (parfum.slug) {
    const real = realImageFor(parfum.slug);
    if (real) return real;
  }
  return size === "banner"
    ? generatePerfumeBanner({
        brand: parfum.marke,
        name: parfum.name,
        family: parfum.duftfamilie,
        slug: parfum.slug,
        brandSlug: parfum.markeSlug,
      })
    : generatePerfumeImage({
        brand: parfum.marke,
        name: parfum.name,
        family: parfum.duftfamilie,
        slug: parfum.slug,
        brandSlug: parfum.markeSlug,
      });
}

/** True if a real product photo has been uploaded for this perfume. */
export function hasRealImage(slug: string | undefined): boolean {
  if (!slug) return false;
  return !!perfumeImageManifest[slug];
}
